import React, { useState } from "react";
import logo from "./images/logo.jpeg";
import AiTeacher from "./images/aiBackground.jpg";
import Container from 'react-bootstrap/Container';
import Nav from 'react-bootstrap/Nav';
import Navbar from 'react-bootstrap/Navbar';
import Row from 'react-bootstrap/Row';
import Col from 'react-bootstrap/Col';
import Button from 'react-bootstrap/Button';
import Form from 'react-bootstrap/Form';
import { useNavigate, Link } from 'react-router-dom';
import Card from 'react-bootstrap/Card';
import "./home2.css";

function HomePage() {
  const [wordsIKindaKnow, setWordsIKindaKnow] = useState(['apple', 'banana', 'cat', 'dog']);
  const [wordsIDontKnow, setWordsIDontKnow] = useState(['caset', 'vreemon', 'cremora']);
  const [wordsIKnow, setWordsIKnow] = useState([]);
  const [currentWordIndex, setCurrentWordIndex] = useState(0);
  const [wordList, setWordList] = useState([...wordsIDontKnow, ...wordsIKindaKnow]);
  const [currentWord, setCurrentWord] = useState(wordList.length > 0 ? wordList[0] : "");
  const [userInput, setUserInput] = useState("");

  const checkAnswer = () => {
    if (userInput.toLowerCase() === currentWord.toLowerCase()) {
      setWordsIKnow([...wordsIKnow, currentWord]);
    } else {
      setWordList([...wordList, currentWord]);
    }

    const newIndex = currentWordIndex + 1;
    if (newIndex < wordList.length) {
      setCurrentWord(wordList[newIndex]);
      setCurrentWordIndex(newIndex);
    } else {
      setCurrentWord("Done!");
    }
    setUserInput("");
  };

  return (
    <div className="app">
      <Navbar bg="light" variant="light" expand="lg">
        <Container>
          <Navbar.Brand href="#home">
            <img
              src={logo}
              width="30"
              height="30"
              className="d-inline-block align-top"
              alt="React Bootstrap logo"
            />
          </Navbar.Brand>
          <Navbar.Toggle aria-controls="basic-navbar-nav" />
          <Navbar.Collapse id="basic-navbar-nav">
            <Nav className="me-auto">
              <Nav.Link as={Link} to="/home">Home</Nav.Link>
              <Nav.Link as={Link} to="/">Login</Nav.Link>
              <Nav.Link as={Link} to="/register">Registration</Nav.Link>
            </Nav>
          </Navbar.Collapse>
        </Container>
      </Navbar>

      <h1 className="big-title">Smart Learning Management System</h1>
      <div className="cards">
        <Card style={{ width: '18rem', margin: 'auto', padding: '20px' }}>
          <Card.Body>
            <Card.Title>Spell the Word</Card.Title>
            <Card.Text>{currentWord}</Card.Text>
            <Form.Control
              type="text"
              value={userInput}
              onChange={(e) => setUserInput(e.target.value)}
              placeholder="Type your answer here"
            />
            <Button onClick={checkAnswer} className="mt-2">Submit</Button>
          </Card.Body>
        </Card>
      </div>
    </div>
  );
}

export default HomePage;
